import { binomialCoeff } from '../src/binomialCoeff'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("5 choose 2", binomialCoeff(5,2), 10)
await check("choose zero is one", binomialCoeff(10,0), 1)
await check("choose all is one", binomialCoeff(10,10), 1)
await check("k greater than n is zero", binomialCoeff(5,6), 0)
await check("negative k is zero", binomialCoeff(5,-1), 0)
await check("central coefficient 20 choose 10", binomialCoeff(20,10), 184756)
await check("symmetry 30 choose 15", binomialCoeff(30,15), 155117520)
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
